    public void run() throws Exception {
        AddressFactory af = currentProgram.getAddressFactory();
        FunctionManager fm = currentProgram.getFunctionManager();
        monitor.initialize(BOUNDS.length);

        // Phase 1: clean slate — delete every existing function (keeps instructions).
        List<Function> existing = new ArrayList<>();
        for (Function f : fm.getFunctions(true)) existing.add(f);
        monitor.setMessage("Clearing " + existing.size() + " existing functions");
        for (Function f : existing) {
            if (monitor.isCancelled()) return;
            removeFunction(f);
        }

        // Phase 2: recreate the exact canonical set.
        int made = 0, failed = 0;
        for (String rec : BOUNDS) {
            if (monitor.isCancelled()) return;
            monitor.incrementProgress(1);
            String[] p = rec.split("\\|", -1);
            long va = Long.parseLong(p[0], 16);
            String conv = p[1];
            Address entry = toAddr(va);
            // Build the exact (possibly multi-range) body.
            AddressSet body = new AddressSet();
            for (String seg : p[2].split(";")) {
                if (seg.isEmpty()) continue;
                int dash = seg.indexOf('-');
                Address s = toAddr(Long.parseLong(seg.substring(0, dash), 16));
                Address e = toAddr(Long.parseLong(seg.substring(dash + 1), 16));
                body.addRange(s, e);
            }
            // Disassemble the WHOLE body (walking gaps), so CreateFunctionCmd can claim it
            // all -- non-contiguous / shared-code bodies have basic blocks reached only by
            // jumps, and flow disassembly can stall mid-body (e.g. 16-bit seg-override ops).
            disasmBody(body);
            try {
                // Remove any stray fn at this entry, then create with the EXACT body.
                // CreateFunctionCmd takes the body directly -> no auto-flow carving, so
                // non-contiguous / shared-code bodies can't collide (canonical bodies are disjoint).
                Function stray = fm.getFunctionAt(entry);
                if (stray != null) removeFunction(stray);
                CreateFunctionCmd cmd = new CreateFunctionCmd((String) null, entry, body, SourceType.USER_DEFINED);
                if (!cmd.applyTo(currentProgram, monitor)) {
                    // Entry not on a clean instruction boundary (auto-analysis mis-decoded
                    // inter-function padding into it). Clear the body's code/data units and
                    // re-disassemble the entry, then retry.
                    clearListing(body);
                    disasmBody(body);
                    cmd = new CreateFunctionCmd((String) null, entry, body, SourceType.USER_DEFINED);
                    if (!cmd.applyTo(currentProgram, monitor)) {
                        failed++;
                        println("boundary FAIL @0x" + Long.toHexString(va) + ": " + cmd.getStatusMsg());
                        continue;
                    }
                }
                Function fn = cmd.getFunction();
                if (fn == null) fn = fm.getFunctionAt(entry);
                if (fn != null && !conv.isEmpty()) {
                    try { fn.setCallingConvention(conv); } catch (Exception ce) { /* spec may lack it */ }
                }
                made++;
            } catch (Exception ex) {
                failed++;
                println("boundary FAIL @0x" + Long.toHexString(va) + ": " + ex.getMessage());
            }
        }
        println("ROTHDefineCanonicalBoundaries: recreated " + made + " functions, " + failed + " failed.");
    }

    // Disassemble every undecoded address inside the body (gap-walk), so flow stalls
    // (16-bit seg-override ops, jump-only-reachable blocks) don't leave holes.
    private void disasmBody(AddressSetView body) throws Exception {
        for (AddressRange r : body) {
            Address a = r.getMinAddress();
            Address rmax = r.getMaxAddress();
            while (a != null && a.compareTo(rmax) <= 0) {
                Instruction ins = getInstructionContaining(a);
                if (ins == null) {
                    disassemble(a);
                    ins = getInstructionAt(a);
                }
                Address nxt = (ins != null) ? ins.getMaxAddress() : a;
                a = nxt.next();
            }
        }
    }
